void test_policy_matches_pytorch(bool& test_failed) {
    float* ref = load_ref("cuda/test/reference_data/startpos_policy.bin", 4672);
    if (!ref) { printf("[no ref data] "); ASSERT_TRUE(true); return; }

    TransformerWeights* d_w = load_transformer_weights("weights/transformer4/candidate_1.bin");
    if (!d_w) { printf("[no weights] "); ASSERT_TRUE(true); free(ref); return; }

    BoardState bs = make_starting_position();
    BoardState* d_bs; cudaMalloc(&d_bs, sizeof(BoardState));
    cudaMemcpy(d_bs, &bs, sizeof(BoardState), cudaMemcpyHostToDevice);

    float *d_policy, *d_val, *d_k;
    cudaMalloc(&d_policy, 4672 * 4); cudaMalloc(&d_val, 4); cudaMalloc(&d_k, 4);

    int smem = TF_SMEM_BYTES;
    cudaFuncSetAttribute(kernel_full_forward, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);
    kernel_full_forward<<<1, 256, smem>>>(d_bs, 0.0f, d_w, d_policy, d_val, d_k);
    cudaDeviceSynchronize();

    float h_policy[4672];
    cudaMemcpy(h_policy, d_policy, sizeof(h_policy), cudaMemcpyDeviceToHost);

    ASSERT_TRUE(!has_nan(h_policy, 4672));
    float md = max_abs_diff(h_policy, ref, 4672);
    float mn = mean_abs_diff(h_policy, ref, 4672);
    printf("[max_diff=%.6f mean=%.6f] ", md, mn);
    ASSERT_TRUE(md < 1e-3f);

    // Check top move matches
    int cuda_top = 0, ref_top = 0;
    for (int i = 1; i < 4672; i++) {
        if (h_policy[i] > h_policy[cuda_top]) cuda_top = i;
        if (ref[i] > ref[ref_top]) ref_top = i;
    }
    printf("[top: cuda=%d ref=%d] ", cuda_top, ref_top);
    ASSERT_EQ(cuda_top, ref_top);

    cudaFree(d_bs); cudaFree(d_policy); cudaFree(d_val); cudaFree(d_k);
    free_transformer_weights(d_w); free(ref);
}

void test_value_matches_pytorch(bool& test_failed) {
    // Reference: [v_logit_q0, value_q0, k, v_logit_q3, value_q3]
    float* ref = load_ref("cuda/test/reference_data/startpos_value.bin", 5);
    if (!ref) { printf("[no ref data] "); ASSERT_TRUE(true); return; }

    TransformerWeights* d_w = load_transformer_weights("weights/transformer4/candidate_1.bin");
    if (!d_w) { printf("[no weights] "); ASSERT_TRUE(true); free(ref); return; }

    BoardState bs = make_starting_position();
    BoardState* d_bs; cudaMalloc(&d_bs, sizeof(BoardState));
    cudaMemcpy(d_bs, &bs, sizeof(BoardState), cudaMemcpyHostToDevice);

    float *d_policy, *d_val, *d_k;
    cudaMalloc(&d_policy, 4672 * 4); cudaMalloc(&d_val, 4); cudaMalloc(&d_k, 4);

    int smem = TF_SMEM_BYTES;
    cudaFuncSetAttribute(kernel_full_forward, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);

    float ref_value_q0 = ref[1], ref_k = ref[2], ref_value_q3 = ref[4];

    // q=0
    kernel_full_forward<<<1, 256, smem>>>(d_bs, 0.0f, d_w, d_policy, d_val, d_k);
    cudaDeviceSynchronize();
    float h_val, h_k;
    cudaMemcpy(&h_val, d_val, 4, cudaMemcpyDeviceToHost);
    cudaMemcpy(&h_k, d_k, 4, cudaMemcpyDeviceToHost);

    printf("[q=0: val=%.6f ref=%.6f] ", h_val, ref_value_q0);
    ASSERT_NEAR(h_val, ref_value_q0, 1e-4f);
    ASSERT_NEAR(h_k, ref_k, 1e-4f);

    // q=3
    kernel_full_forward<<<1, 256, smem>>>(d_bs, 3.0f, d_w, d_policy, d_val, d_k);
    cudaDeviceSynchronize();
    cudaMemcpy(&h_val, d_val, 4, cudaMemcpyDeviceToHost);

    printf("[q=3: val=%.6f ref=%.6f] ", h_val, ref_value_q3);
    ASSERT_NEAR(h_val, ref_value_q3, 1e-4f);

    cudaFree(d_bs); cudaFree(d_policy); cudaFree(d_val); cudaFree(d_k);
    free_transformer_weights(d_w); free(ref);
}

void test_no_nan_in_forward_pass(bool& test_failed) {
    TransformerWeights* d_w = load_transformer_weights("weights/transformer4/candidate_1.bin");
    if (!d_w) { printf("[no weights] "); ASSERT_TRUE(true); return; }

    BoardState bs = make_starting_position();
    BoardState* d_bs; cudaMalloc(&d_bs, sizeof(BoardState));
    cudaMemcpy(d_bs, &bs, sizeof(BoardState), cudaMemcpyHostToDevice);

    float *d_policy, *d_val, *d_k;
    cudaMalloc(&d_policy, 4672 * 4); cudaMalloc(&d_val, 4); cudaMalloc(&d_k, 4);

    int smem = TF_SMEM_BYTES;
    cudaFuncSetAttribute(kernel_full_forward, cudaFuncAttributeMaxDynamicSharedMemorySize, smem);
    kernel_full_forward<<<1, 256, smem>>>(d_bs, 0.0f, d_w, d_policy, d_val, d_k);
    cudaDeviceSynchronize();

    float h_policy[4672], h_val;
    cudaMemcpy(h_policy, d_policy, sizeof(h_policy), cudaMemcpyDeviceToHost);
    cudaMemcpy(&h_val, d_val, 4, cudaMemcpyDeviceToHost);

    ASSERT_TRUE(!has_nan(h_policy, 4672));
    ASSERT_TRUE(!isnan(h_val));

    cudaFree(d_bs); cudaFree(d_policy); cudaFree(d_val); cudaFree(d_k);
    free_transformer_weights(d_w);
}

// ============================================================
// Main
// ============================================================

int main() {
    printf("=== Transformer vs PyTorch Regression Tests ===\n");
    init_movegen_tables();
    cudaDeviceSetLimit(cudaLimitStackSize, 32768);

    int total = 0, passes = 0, failures = 0;

    RUN_TEST(test_board_encoding_matches_reference);
    RUN_TEST(test_input_proj_matches_pytorch);
    RUN_TEST(test_posemb_matches_pytorch);
    RUN_TEST(test_block0_matches_pytorch);
    RUN_TEST(test_block5_matches_pytorch);
    RUN_TEST(test_policy_matches_pytorch);
    RUN_TEST(test_value_matches_pytorch);
    RUN_TEST(test_no_nan_in_forward_pass);

    printf("\n%d/%d tests passed", passes, total);
    if (failures > 0) printf(", %d FAILED", failures);
    printf("\n");
    return failures > 0 ? 1 : 0;
}
